/* Met à jour ImageUrl des produits avec de vraies photos loremflickr.com
   La photo est déterminée par le nom de la catégorie du produit. */

UPDATE Produits SET ImageUrl = N'https://loremflickr.com/400/400/paper,office?lock=' + CAST(Produits.Id AS NVARCHAR(10)) FROM Produits INNER JOIN Categories ON Produits.CategorieId = Categories.Id WHERE Categories.Nom = N'Papier A4' AND (Produits.ImageUrl = N'/images/placeholder.png' OR Produits.ImageUrl LIKE N'%placeholder%' OR Produits.ImageUrl = N'');
